        MOD = 10**9 + 7

        def to_base(n, base):
            if n == 0:
                return "0"
            digits = []
            while n > 0:
                digits.append(str(n % base))
                n //= base
            return ''.join(reversed(digits)) if digits else "0"

        def is_non_decreasing(s):
            for i in range(1, len(s)):
