            n = 0
            for ch in num_str:
                n = n * 10 + int(ch)
            num = n

            max_len = 0
            temp = num
            if temp == 0:
                max_len = 1
            else:
                max_len = 0
                while temp > 0:
                    temp //= base
                    max_len += 1

            from functools import lru_cache

            s = to_base(num, base)

            @lru_cache(maxsize=None)
            def dp(pos, tight, last_digit, started):
                if pos == len(s):
                    return 1 if started else 0
                limit = int(s[pos]) if tight else base - 1
                total = 0
                for d in range(0, limit + 1):
                    new_tight = tight and (d == limit)
                    new_started = started or (d != 0)
                    if not new_started:
                        total += dp(pos + 1, new_tight, last_digit, new_started)
                    else:
                        if last_digit is None or d >= last_digit:
                            total += dp(pos + 1, new_tight, d, new_started)
                    total %= MOD
                return total

            result = dp(0, True, None, False)
            dp.cache_clear()
            return result

